def parse_random(expression: str):
    """Parse random expression 'm1*m2[*mN]'.

    Returns list of canonical model names, or None if not a random expression.
    Raises ValueError for malformed expressions.
    """
    if "|" in expression or "->" in expression or "+" in expression:
        return None
    if "*" not in expression:
        return None
    parts = expression.split("*")
    models = [p.strip() for p in parts if p.strip()]
    if len(models) < 2:
        raise ValueError("Random mode requires at least 2 models")
    models = [SHORT_ALIASES.get(m, m) for m in models]
    for m in models:
        if m not in KNOWN_MODELS:
            raise ValueError(f"Invalid model: {m}")
    if len(models) != len(set(models)):
        raise ValueError("Duplicate models not allowed")
    return models


def parse_failover(expression: str):
    """Parse failover expression 'm1|m2[|mN]'.

    Returns list of canonical model names, or None if not a failover expression.
    Raises ValueError for malformed expressions.
    """
    if "*" in expression or "->" in expression or "+" in expression:
        return None
    if "|" not in expression:
        return None
    parts = expression.split("|")
    models = [p.strip() for p in parts if p.strip()]
    if len(models) < 2:
        raise ValueError("Failover mode requires at least 2 models")
    models = [SHORT_ALIASES.get(m, m) for m in models]
    for m in models:
        if m not in KNOWN_MODELS:
            raise ValueError(f"Invalid model: {m}")
    if len(models) != len(set(models)):
        raise ValueError("Duplicate models not allowed")
    return models


def _reviewer_name_for(hook_model: str, provider) -> str:
    """Determine reviewer label from model string and provider instance."""
    if isinstance(provider, CodexProvider):
        return "codex-gpt5"
    from .gemini_provider import GeminiProvider

    if isinstance(provider, GeminiProvider):
        return "gem-flash" if hook_model == "gemini-flash" else "gem-pro"
    return "anthropic-sdk"


def _sdk_fallback(prompt, system_prompt, call_context, max_thinking_tokens):
    """Call Anthropic SDK as last-resort fallback."""
    from .anthropic_provider import AnthropicProvider

    fallback = AnthropicProvider()
    hint = resolve_model_for_call("auto", call_context)
    response = fallback.query(prompt, system_prompt, hint, max_thinking_tokens)
    return response, _REVIEWER_SDK


